from dataclasses import dataclass, field
from enum import Enum
from typing import Callable


class GateStatus(Enum):
    OPEN = "open"
    PASSED = "passed"
    FAILED = "failed"


@dataclass
class IntegrationGate:
    name: str
    criterion: str
    check: Callable[[], bool]
    owner_art: str

    def evaluate(self) -> GateStatus:
        return GateStatus.PASSED if self.check() else GateStatus.FAILED


@dataclass
class IntegrationMilestone:
    name: str
    sprint: int
    gates: list[IntegrationGate] = field(default_factory=list)

    def add_gate(self, gate: IntegrationGate) -> None:
        self.gates.append(gate)

    def run_all_gates(self) -> dict[str, GateStatus]:
        results = {}
        for gate in self.gates:
            results[gate.name] = gate.evaluate()
        return results

    def is_passed(self) -> bool:
        return all(
            s == GateStatus.PASSED
            for s in self.run_all_gates().values()
        )


# Example: IM-1 gate checks
im1 = IntegrationMilestone(name="IM-1: Platform API Freeze", sprint=2)

im1.add_gate(IntegrationGate(
    name="Model contract registered",
    criterion="summariser-v2 contract is ACTIVE in registry",
    check=lambda: True,   # replace with real registry lookup
    owner_art="Foundation Models ART",
))
im1.add_gate(IntegrationGate(
    name="Consumer ARTs confirmed",
    criterion="All consumer ARTs acknowledged the frozen API",
    check=lambda: True,
    owner_art="GenAI Platform ART",
))

results = im1.run_all_gates()
for gate_name, status in results.items():
    print(f"  {'✓' if status == GateStatus.PASSED else '✗'} {gate_name}: {status.value}")
print(f"IM-1 overall: {'PASSED' if im1.is_passed() else 'FAILED'}")

from dataclasses import dataclass, field
from datetime import date


@dataclass
class ContractBreachEvent:
    date_occurred: date
    model_id: str
    consumer_art: str
    sprint_lost: float   # sprint-days lost due to the unannounced change
    root_cause: str


@dataclass
class ContractBreachRegister:
    pi_id: str
    total_integration_events: int
    breaches: list[ContractBreachEvent] = field(default_factory=list)

    def add_breach(self, breach: ContractBreachEvent) -> None:
        self.breaches.append(breach)

    def breach_rate_per_100(self) -> float:
        if self.total_integration_events == 0:
            return 0.0
        return (len(self.breaches) / self.total_integration_events) * 100

    def total_sprint_days_lost(self) -> float:
        return sum(b.sprint_lost for b in self.breaches)

    def report(self) -> None:
        print(f"PI {self.pi_id} Contract Breach Report")
        print(f"  Breaches: {len(self.breaches)} / {self.total_integration_events} events")
        print(f"  Breach rate: {self.breach_rate_per_100():.1f} per 100 events")
        print(f"  Sprint-days lost: {self.total_sprint_days_lost():.1f}")
        if self.breaches:
            print("  Root causes:")
            for b in self.breaches:
                print(f"    - {b.model_id} → {b.consumer_art}: {b.root_cause}")


register = ContractBreachRegister(pi_id="PI-2026-Q3", total_integration_events=48)
register.add_breach(ContractBreachEvent(
    date_occurred=date(2026, 7, 14),
    model_id="summariser-v2",
    consumer_art="Product Features ART",
    sprint_lost=1.5,
    root_cause="Provider ART bumped minor version without consumer notification",
))
register.report()

from dataclasses import dataclass


@dataclass
class ComputeSprintActuals:
    art: str
    sprint: int
    planned_gpu_h: float
    actual_gpu_h: float

    def variance_pct(self) -> float:
        if self.planned_gpu_h == 0:
            return 0.0
        return ((self.actual_gpu_h - self.planned_gpu_h) / self.planned_gpu_h) * 100

    def flag(self) -> str:
        v = self.variance_pct()
        if v > 15:
            return "OVER — investigate unplanned work"
        if v < -15:
            return "UNDER — check if work is being deferred"
        return "OK"


actuals = [
    ComputeSprintActuals("Foundation Models ART", sprint=3, planned_gpu_h=240, actual_gpu_h=310),
    ComputeSprintActuals("GenAI Platform ART",    sprint=3, planned_gpu_h=80,  actual_gpu_h=76),
    ComputeSprintActuals("Product Features ART",  sprint=3, planned_gpu_h=40,  actual_gpu_h=41),
]

for a in actuals:
    print(f"  {a.art} S{a.sprint}: {a.actual_gpu_h:.0f}/{a.planned_gpu_h:.0f} GPU-h "
          f"({a.variance_pct():+.0f}%) → {a.flag()}")
